#include <stdio.h>

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long X, Y; scanf("%lld %lld", &X, &Y);
        long long ans;
        if (Y == 0) ans = X;
        else if (X == Y) ans = 2 * Y - 1;
        else ans = X + Y;
        printf("%lld\n", ans);
    }
    return 0;
}

